/dts-v1/;
/ {
    compatible = "my_board";

    memory {
        device_type = "memory";
        reg = <0x80000000 0x40000000>;  // Start address and size
    };

    soc {
        compatible = "simple-bus";
        #address-cells = <1>;
        #size-cells = <1>;

        uart@1000 {
            compatible = "ns16550a";
            reg = <0x1000 0x100>;
            interrupt-parent = <&intc>;
            interrupts = <5>;
        };

        gpio@2000 {
            compatible = "my_gpio";
            reg = <0x2000 0x100>;
        };
    };
};
